// Workers KV simple read/write
async function handle(event) {
  // READ from KV (local replica)
  const val = await MY_KV.get('counter')
  // WRITE to KV (asynchronous replication)
  await MY_KV.put('counter', (parseInt(val || '0') + 1).toString())
  return new Response('counter=' + (parseInt(val || '0') + 1))
}

// Durable Object class (simplified)
export class Counter {
  constructor(state, env) {
    this.state = state
  }
  async fetch(req) {
    const cur = (await this.state.storage.get('v')) || 0
    await this.state.storage.put('v', cur + 1)
    return new Response('do-counter=' + (cur + 1))
  }
}

