/* Orchestrator (simple Python Flask-like pseudocode) */
from uuid import uuid4

saga_store = {}

def start_booking(payload):
    saga_id = str(uuid4())
    saga_store[saga_id] = {'steps': [], 'status': 'in_progress'}
    try:
        flight = call_service('flight.reserve', payload['flight'])
        saga_store[saga_id]['steps'].append(('flight_reserved', flight['id']))

        hotel = call_service('hotel.reserve', payload['hotel'])
        saga_store[saga_id]['steps'].append(('hotel_reserved', hotel['id']))

        payment = call_service('payment.charge', payload['payment'])
        saga_store[saga_id]['steps'].append(('payment_charged', payment['id']))

        saga_store[saga_id]['status'] = 'completed'
        return {'saga_id': saga_id, 'result': 'success'}
    except Exception as e:
        compensate(saga_store[saga_id]['steps'])
        saga_store[saga_id]['status'] = 'failed'
        return {'saga_id': saga_id, 'result': 'failed', 'reason': str(e)}

def compensate(steps):
    # reverse order
    for step, resource_id in reversed(steps):
        if step == 'hotel_reserved':
            call_service('hotel.cancel', {'id': resource_id})
        if step == 'flight_reserved':
            call_service('flight.cancel', {'id': resource_id})
        if step == 'payment_charged':
            call_service('payment.refund', {'id': resource_id})
